+#[test]
+fn loom_parker_unpark_before_park() {
+    loom::model(|| {
+        let parker = Arc::new(LoomParker::new());
+
+        // Unpark first (store permit)
+        parker.unpark();
+
+        let p = parker.clone();
+        let h = thread::spawn(move || {
+            p.park(); // Should consume permit and return immediately
+        });
+
+        h.join().unwrap();
+    });
+}
